class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: GetEnvironmentVariable returns empty string
        // instead of null for variables set to "". Use explicit check for both.
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val is null || val.Length == 0)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

